// src/parser/frontmatter.rs
use serde::Deserialize;
use yaml_rust::YamlLoader;

#[derive(Debug, Deserialize, Clone)]
pub struct Frontmatter {
    pub title: String,
    pub date: Option<String>,
    pub tags: Option<Vec<String>>,
    pub template: Option<String>,
    pub draft: Option<bool>,
}

pub fn parse(content: &str) -> Result<(Frontmatter, &str), ParseError> {
    if !content.starts_with("---") {
        return Err(ParseError::NoFrontmatter);
    }
    let end = content[3..].find("---")
        .ok_or(ParseError::Unterminated)?;
    let yaml_str = &content[3..end + 3];
    let body = &content[end + 6..];
    let fm: Frontmatter = serde_yaml::from_str(yaml_str)?;
    Ok((fm, body.trim_start()))
}

// src/generator/toc.rs
use pulldown_cmark::{Event, Tag, Parser};

pub struct TocEntry {
    pub level: u32,
    pub id: String,
    pub title: String,
}

pub fn generate_toc(markdown: &str) -> Vec<TocEntry> {
    let parser = Parser::new(markdown);
    let mut entries = Vec::new();
    let mut current_level = 0;
    let mut current_text = String::new();
    for event in parser {
        match event {
            Event::Start(Tag::Heading(level, ..)) => {
                current_level = level as u32;
                current_text.clear();
            }
            Event::Text(text) if current_level > 0 => {
                current_text.push_str(&text);
            }
            Event::End(Tag::Heading(..)) => {
                let id = slugify(&current_text);
                entries.push(TocEntry { level: current_level, id, title: current_text.clone() });
                current_level = 0;
            }
            _ => {}
        }
    }
    entries
}

// src/server/ot/transform.ts
import { Operation, OpType } from '../../shared/types';

export function transform(
  op1: Operation,
  op2: Operation
): [Operation, Operation] {
  if (op1.type === OpType.Draw && op2.type === OpType.Draw) {
    // Independent draws don't conflict
    return [op1, op2];
  }
  if (op1.type === OpType.Erase && op2.type === OpType.Draw) {
    if (overlaps(op1.region, op2.path)) {
      // Erase wins over draw in same region
      return [op1, { ...op2, cancelled: true }];
    }
  }
  if (op1.type === OpType.Move && op2.type === OpType.Move) {
    // Both moving same object - last writer wins by timestamp
    if (op1.targetId === op2.targetId) {
      return op1.timestamp > op2.timestamp
        ? [op1, { ...op2, cancelled: true }]
        : [{ ...op1, cancelled: true }, op2];
    }
  }
  return [op1, op2];
}

