# datapipe/pipeline.py
from typing import Iterator, Dict, Any
from datapipe.reader import CSVReader
from datapipe.writer import get_writer
from datapipe.schema import SchemaValidator

class Pipeline:
    def __init__(self, config: Dict[str, Any]):
        self.reader = CSVReader(**config.get('input', {}))
        self.transforms = []
        self.writer = get_writer(config.get('output', {}))
        self.validator = SchemaValidator(config.get('schema'))

    def add_transform(self, transform):
        self.transforms.append(transform)
        return self

    def run(self, streaming: bool = False) -> None:
        if streaming:
            self._run_streaming()
        else:
            self._run_batch()

    def _run_streaming(self) -> None:
        for chunk in self.reader.read_chunks(chunk_size=10000):
            validated = self.validator.validate(chunk)
            for transform in self.transforms:
                validated = transform.apply(validated)
            self.writer.write(validated, append=True)

    def _run_batch(self) -> None:
        data = self.reader.read_all()
        validated = self.validator.validate(data)
        for transform in self.transforms:
            validated = transform.apply(validated)
        self.writer.write(validated)

# datapipe/schema.py
import pandas as pd
from typing import Optional, Dict

class SchemaValidator:
    def __init__(self, schema: Optional[Dict] = None):
        self.schema = schema
        self.inferred = None

    def validate(self, df: pd.DataFrame) -> pd.DataFrame:
        if self.schema is None:
            self.inferred = self._infer_schema(df)
            return df
        for col, dtype in self.schema.items():
            if col not in df.columns:
                raise SchemaError(f"Missing column: {col}")
            df[col] = df[col].astype(dtype)
        return df

    def _infer_schema(self, df: pd.DataFrame) -> Dict:
        return {col: str(df[col].dtype) for col in df.columns}

