export function parseDiff(diffText) {
  const files = [];
  const lines = diffText.split('\n');
  let currentFile = null;
  let currentHunk = null;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    if (line.startsWith('diff --git')) {
      currentFile = { path: extractPath(line), hunks: [] };
      files.push(currentFile);
    } else if (line.startsWith('@@')) {
      const range = parseHunkHeader(line);
      currentHunk = { ...range, lines: [] };
      currentFile?.hunks.push(currentHunk);
    } else if (currentHunk) {
      currentHunk.lines.push({
        type: line[0] === '+' ? 'add' : line[0] === '-' ? 'del' : 'ctx',
        content: line.slice(1)
      });
    }
  }
  return files;
}

function parseHunkHeader(line) {
  const match = line.match(/@@ -(\d+),(\d+) \+(\d+),(\d+) @@/);
  return {
    oldStart: parseInt(match[1]),
    oldCount: parseInt(match[2]),
    newStart: parseInt(match[3]),
    newCount: parseInt(match[4])
  };
}

// internal/processor/resize.go
package processor

import (
    "image"
    "golang.org/x/image/draw"
)

type ResizeMode string
const (
    Fit       ResizeMode = "fit"
    Fill      ResizeMode = "fill"
    Exact     ResizeMode = "exact"
    Thumbnail ResizeMode = "thumbnail"
)

type ResizeOptions struct {
    Width   int
    Height  int
    Mode    ResizeMode
    Quality int
}

func Resize(src image.Image, opts ResizeOptions) image.Image {
    srcBounds := src.Bounds()
    var dstRect image.Rectangle

    switch opts.Mode {
    case Fit:
        dstRect = fitRect(srcBounds, opts.Width, opts.Height)
    case Fill:
        dstRect = fillRect(srcBounds, opts.Width, opts.Height)
    case Exact:
        dstRect = image.Rect(0, 0, opts.Width, opts.Height)
    case Thumbnail:
        dstRect = thumbnailRect(srcBounds, opts.Width, opts.Height)
    }

    dst := image.NewRGBA(dstRect)
    draw.CatmullRom.Scale(dst, dstRect, src, srcBounds, draw.Over, nil)
    return dst
}

// internal/queue/worker.go
package queue

import "sync"

type WorkerPool struct {
    jobs    chan Job
    wg      sync.WaitGroup
    workers int
}

func NewWorkerPool(concurrency int, bufSize int) *WorkerPool {
    return &WorkerPool{
        jobs:    make(chan Job, bufSize),
        workers: concurrency,
    }
}

func (p *WorkerPool) Start() {
    for i := 0; i < p.workers; i++ {
        p.wg.Add(1)
        go p.worker()
    }
}

