from typing import List, Optional
from migrator.history import MigrationHistory

class MigrationEngine:
    def __init__(self, driver, dry_run: bool = False):
        self.driver = driver
        self.history = MigrationHistory(driver)
        self.dry_run = dry_run

    def migrate_up(self, target: Optional[str] = None) -> List[str]:
        pending = self.history.get_pending()
        applied = []
        for migration in pending:
            if target and migration.name > target:
                break
            if self.dry_run:
                sql = migration.up_sql()
                print(f"-- Would execute: {migration.name}")
                print(sql)
            else:
                with self.driver.transaction():
                    migration.up(self.driver)
                    self.history.mark_applied(migration.name)
            applied.append(migration.name)
        return applied

    def migrate_down(self, steps: int = 1) -> List[str]:
        applied = self.history.get_applied()[-steps:]
        reverted = []
        for migration in reversed(applied):
            if self.dry_run:
                print(f"-- Would revert: {migration.name}")
            else:
                with self.driver.transaction():
                    migration.down(self.driver)
                    self.history.mark_reverted(migration.name)
            reverted.append(migration.name)
        return reverted
